const express = require("express");
const cors = require("cors");
const bodyParser = require("body-parser");

const app = express();

app.use(cors());
app.use(bodyParser.json());

// BASE DE DADOS SIMPLES
let projetos = [
    { id: 1, nome: "Sistema Escolar", descricao: "Gestão de alunos e notas" },
    { id: 2, nome: "App Delivery", descricao: "Pedidos online com rastreio" },
    { id: 3, nome: "Portfólio Web", descricao: "Site profissional moderno" }
];

// API: projetos
app.get("/api/projetos", (req, res) => {
    res.json(projetos);
});

// API: contacto
let mensagens = [];

app.post("/api/contacto", (req, res) => {
    mensagens.push(req.body);
    res.json({ message: "Mensagem enviada com sucesso!" });
});

// iniciar servidor
app.listen(3000, () => {
    console.log("Servidor a correr em http://localhost:3000");
});